import oauthlib
from flask import Flask, request, jsonify

app = Flask(__name__)

# Registered base URL for the authorization server
registered_uri = "https://example.com"

@app.route("/oauth/authorize", methods=["GET"])
def authorize():
    redirect_uri = request.args.get("redirect_uri")
    if not redirect_uri:
        return jsonify({"error": "invalid_request"}), 400
    if not redirect_uri.startswith(registered_uri):
        return jsonify({"error": "invalid_redirect_uri"}), 401
